# -*- coding: utf-8 -*-import base64from odoo import models, fields, api, _from odoo.exceptions import AccessError, UserError, ValidationErrorfrom lxml import etree as ETimport jsonclass InvestmentCategory(models.Model):    _name = 'investment.category'    _inherit = ['mail.thread', 'mail.activity.mixin', 'portal.mixin']    _description = "Investment Category"    company_id = fields.Many2one('res.company', default=lambda self: self.env.company, tracking=True)    name = fields.Char(tracking=True)    minimum_amount = fields.Float(string="Minimum Amount", tracking=True)    maximum_amount = fields.Float(string="Maximum Amount", tracking=True)